namespace sv_94c8791ee6bb44ffbeba30be7f11601a.Models;

public class ApplicationData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<JobHistoryEntry> Experience { get; set; } = new();
    public List<ReferenceContact> References { get; set; } = new();
    public int CompletedStep { get; set; }
}

public class PersonalInfo
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class JobHistoryEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_94c8791ee6bb44ffbeba30be7f11601a.Models;

namespace sv_94c8791ee6bb44ffbeba30be7f11601a.Services;

/// <summary>
/// Singleton store for wizard data, keyed by ASP.NET session ID.
/// Accessible from both static SSR (layout) and interactive server (pages).
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionKey)
        => _store.GetOrAdd(sessionKey, _ => new ApplicationData());
}

@inherits LayoutComponentBase
@layout MainLayout
@inject sv_94c8791ee6bb44ffbeba30be7f11601a.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

@{
    var sessionKey = HttpContextAccessor.HttpContext?.Session.Id ?? "";
    var data = Store.GetOrCreate(sessionKey);
    var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 1
    };
}

<CascadingValue Value="sessionKey" Name="SessionKey">
    <div class="wizard-header mb-4">
        <h4>Job Application — Step @currentStep of 4</h4>
        <nav class="d-flex gap-2 mb-2">
            @for (int i = 1; i <= 4; i++)
            {
                var step = i;
                var label = step switch
                {
                    1 => "Personal Info",
                    2 => "Experience",
                    3 => "References",
                    _ => "Review"
                };
                var url = step switch
                {
                    1 => "/apply/personal-info",
                    2 => "/apply/experience",
                    3 => "/apply/references",
                    _ => "/apply/review"
                };
                var isActive = step == currentStep;
                var isCompleted = step <= data.CompletedStep;
                <a href="@url"
                   class="btn btn-sm @(isActive ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")">
                    @if (isCompleted && !isActive)
                    {
                        <span>✓ </span>
                    }
                    @label
                </a>
            }
        </nav>
        <div class="progress" style="height: 6px;">
            <div class="progress-bar" role="progressbar"
                 style="width: @(currentStep * 25)%"
                 aria-valuenow="@currentStep" aria-valuemin="0" aria-valuemax="4">
            </div>
        </div>
    </div>

    @Body
</CascadingValue>

