@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_94c8791ee6bb44ffbeba30be7f11601a.Services.WizardStateStore Store
@inject NavigationManager Nav

<PageTitle>Personal Info</PageTitle>
<h5>Personal Information</h5>

<EditForm Model="model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="model.Email" />
    </div>
    <div class="d-flex justify-content-end">
        <button type="submit" class="btn btn-primary">Next →</button>
    </div>
</EditForm>

@code {
    [CascadingParameter(Name = "SessionKey")]
    public string SessionKey { get; set; } = "";

    private PersonalInfo model = new();

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionKey))
        {
            var data = Store.GetOrCreate(SessionKey);
            model = data.PersonalInfo;
        }
    }

    private void Next()
    {
        var data = Store.GetOrCreate(SessionKey);
        data.PersonalInfo = model;
        if (data.CompletedStep < 1) data.CompletedStep = 1;
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_94c8791ee6bb44ffbeba30be7f11601a.Services.WizardStateStore Store
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>
<h5>Work Experience</h5>

@for (int i = 0; i < entries.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Entry @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entries[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entries[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Duration</label>
            <input class="form-control" @bind="entries[index].Duration" placeholder="e.g. 2 years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">+ Add Entry</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    [CascadingParameter(Name = "SessionKey")]
    public string SessionKey { get; set; } = "";

    private List<JobHistoryEntry> entries = new();

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionKey))
        {
            var data = Store.GetOrCreate(SessionKey);
            // Work on a copy of the list but share the entry objects for binding
            entries = data.Experience;
            if (entries.Count == 0)
                entries.Add(new JobHistoryEntry());
        }
    }

    private void AddEntry() => entries.Add(new JobHistoryEntry());
    private void RemoveEntry(int index) { if (entries.Count > 0) entries.RemoveAt(index); }

    private void Save()
    {
        var data = Store.GetOrCreate(SessionKey);
        data.Experience = entries;
        if (data.CompletedStep < 2) data.CompletedStep = 2;
    }

    private void Next() { Save(); Nav.NavigateTo("/apply/references"); }
    private void Back() { Save(); Nav.NavigateTo("/apply/personal-info"); }
}

