@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inject sv_94c8791ee6bb44ffbeba30be7f11601a.Services.WizardStateStore Store
@inject NavigationManager Nav

<PageTitle>Review Application</PageTitle>
<h5>Review Your Application</h5>

@if (data is not null)
{
    <div class="card mb-3 p-3">
        <h6>Personal Information</h6>
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@data.PersonalInfo.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@data.PersonalInfo.Email</dd>
        </dl>
    </div>

    <div class="card mb-3 p-3">
        <h6>Work Experience</h6>
        @if (data.Experience.Count == 0)
        {
            <p class="text-muted">No entries provided.</p>
        }
        else
        {
            @foreach (var job in data.Experience)
            {
                <div class="border-bottom pb-2 mb-2">
                    <strong>@job.Title</strong> at @job.Company
                    <br /><small class="text-muted">@job.Duration</small>
                </div>
            }
        }
    </div>

    <div class="card mb-3 p-3">
        <h6>References</h6>
        @if (data.References.Count == 0)
        {
            <p class="text-muted">No references provided.</p>
        }
        else
        {
            @foreach (var r in data.References)
            {
                <div class="border-bottom pb-2 mb-2">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br /><small class="text-muted">@r.Email</small>
                </div>
            }
        }
    </div>

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Your application has been submitted!</div>
    }
}

@code {
    [CascadingParameter(Name = "SessionKey")]
    public string SessionKey { get; set; } = "";

    private ApplicationData? data;
    private bool submitted;

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionKey))
        {
            data = Store.GetOrCreate(SessionKey);
        }
    }

    private void Submit()
    {
        if (data is not null && data.CompletedStep < 4)
            data.CompletedStep = 4;
        submitted = true;
    }

    private void Back() => Nav.NavigateTo("/apply/references");
}

